function debounce(fn, delay, options = {}) {
  const { leading = false, trailing = true } = options;
  let timer = null;
  let lastArgs = null;
  let hasPendingCall = false;

  const invoke = (context, args, now) => {
    fn.apply(context, args);
    timer = null;
    hasPendingCall = false;
  };

  const debounced = function (...args) {
    const context = this;

    // 如果 trailing 和 leading 都关闭，什么都不做
    if (!leading && !trailing) return;

    const callNow = leading && timer === null;

    // 每次调用清除上一次的 timer
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }

    lastArgs = args;
    hasPendingCall = true;

    if (callNow) {
      // leading 模式：立即执行
      invoke(context, args, true);
    }

    // 设置 trailing 的定时器
    timer = setTimeout(() => {
      if (trailing && hasPendingCall) {
        invoke(context, debounced.lastArgs || lastArgs, false);
      }
      timer = null;
    }, delay);
  };

  // 取消 pending 调用
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    hasPendingCall = false;
    lastArgs = null;
  };

  // 立即执行 pending 调用
  debounced.flush = function () {
    if (timer && hasPendingCall) {
      clearTimeout(timer);
      invoke(this, lastArgs, false);
    }
  };

  return debounced;
}
```

**用法示例：**

```javascript
// 搜索输入防抖，用户停止输入 300ms 后触发
const searchInput = document.getElementById('search');
const handleSearch = debounce((e) => {
  fetchSearchResults(e.target.value);
}, 300);

searchInput.addEventListener('input', handleSearch);

// leading 模式：第一次点击立即执行，后续快速点击被抑制
const saveBtn = document.getElementById('save');
const handleSave = debounce(() => {
  submitForm();
}, 500, { leading: true, trailing: false });

saveBtn.addEventListener('click', handleSave);
```

**三种模式说明：**

| 参数 | 行为 |
|------|------|
| `{ leading: false, trailing: true }`（默认） | 停止触发后 delay 毫秒执行 |
| `{ leading: true, trailing: false }` | 第一次触发立即执行，后续忽略 |
| `{ leading: true, trailing: true }` | 第一次立即执行，停止后 delay 毫秒再执行最后一次 |

`cancel()` 用于清理 pending 调用（组件卸载时），`flush()` 用于立即强制执行 pending 调用（表单提交前）。

